import React, { useEffect, useState } from 'react';
import { getProducts } from '../services/productService';
import ProductCard from '../components/organisms/ProductCard/ProductCard';
import CartView from '../components/organisms/Cart/CartView';
import { useCart } from '../context/CartContext';
import { Button } from '../components/atoms';
import { useNavigate } from 'react-router-dom';
import './EmployeeDashboard.css';

export default function EmployeeDashboard() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState("Todos");
  const { cartItems, subtotal, tax, total } = useCart();
  const navigate = useNavigate();

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const data = await getProducts();
        // Assuming data is an array or has a data property
        setProducts(data.data || data || []);
      } catch (error) {
        console.error("Error fetching products", error);
      } finally {
        setLoading(false);
      }
    };
    fetchProducts();
  }, []);

  // Get unique categories from products
  const categories = ["Todos", ...new Set(products.map(p => p.category).filter(Boolean))];

  const filteredProducts = selectedCategory === "Todos"
    ? products
    : products.filter(p => p.category === selectedCategory);

  return (
    <div className="employee-dashboard">
      <div className="products-section">
        <div className="employee-actions" style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', marginBottom: '1.5rem' }}>
          <h2>Productos</h2>

          {/* Category Filter Tabs */}
          {!loading && (
            <div className="category-tabs" style={{ display: 'flex', gap: '0.5rem', overflowX: 'auto', paddingBottom: '0.5rem' }}>
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  style={{
                    padding: '0.4rem 1rem',
                    borderRadius: '20px',
                    border: '1px solid #e2e8f0',
                    backgroundColor: selectedCategory === cat ? '#22c55e' : '#ffffff',
                    color: selectedCategory === cat ? '#ffffff' : '#475569',
                    cursor: 'pointer',
                    fontWeight: '600',
                    fontSize: '0.85rem',
                    whiteSpace: 'nowrap',
                    transition: 'all 0.2s ease',
                    boxShadow: '0 1px 2px rgba(0,0,0,0.05)'
                  }}
                >
                  {cat}
                </button>
              ))}
            </div>
          )}
        </div>

        {loading ? (
          <p>Cargando productos...</p>
        ) : (
          <div className="products-grid">
            {filteredProducts.map(product => (
              <ProductCard key={product._id} product={product} />
            ))}
          </div>
        )}
      </div>

      <div className="cart-section">
        <div className="cart-actions-header">
          <Button variant="secondary" onClick={() => navigate('/orders')}>Ver Órdenes</Button>
          <Button variant="outline" onClick={() => navigate('/register-client')}>Registrar Cliente / Invitado</Button>
        </div>

        <div className="cart-content-wrapper">
          <CartView />

          <div className="cart-summary">
            <div className="summary-row">
              <span>Subtotal:</span>
              <span>${subtotal?.toFixed(2) || '0.00'}</span>
            </div>
            <div className="summary-row">
              <span>Impuesto (16%):</span>
              <span>${tax?.toFixed(2) || '0.00'}</span>
            </div>
            <div className="summary-row total">
              <span>Total:</span>
              <span>${total?.toFixed(2) || '0.00'}</span>
            </div>
            <Button
              variant="primary"
              className="checkout-btn"
              onClick={() => navigate('/checkout')}
              disabled={!cartItems || cartItems.length === 0}
            >
              Cobrar
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}
